// 全局单例，跨页面共享位置
const btnX = ref\(20\)
const btnY = ref\(500\)

export function useFloatPhone\(\) {
  function clamp\(val: number, min: number, max: number\) {
    return Math.min\(Math.max\(val, min\), max\)
  }

  const dragging = ref\(false\)
  let startX = 0
  let startY = 0
  let startBtnX = 0
  let startBtnY = 0

  function onTouchStart\(e: any\) {
    dragging.value = false
    startX = e.touches[0].clientX
    startY = e.touches[0].clientY
    startBtnX = btnX.value
    startBtnY = btnY.value
  }

  function onTouchMove\(e: any\) {
    const dx = e.touches[0].clientX - startX
    const dy = e.touches[0].clientY - startY
    if \(Math.abs\(dx\) > 5 || Math.abs\(dy\) > 5\) dragging.value = true
    const { windowWidth, windowHeight } = uni.getSystemInfoSync\(\)
    btnX.value = clamp\(startBtnX + dx, 0, windowWidth - 56\)
    btnY.value = clamp\(startBtnY + dy, 0, windowHeight - 56 - 50\) // 50 = tabbar
  }

  function onTouchEnd\(\) {
    if \(!dragging.value\) {
      uni.makePhoneCall\({ phoneNumber: '400-000-0000' }\)
    }
    dragging.value = false
  }

  return { btnX, btnY, onTouchStart, onTouchMove, onTouchEnd }
}
